	if err != nil {
		return nil, fmt.Errorf("GetWatermarkPresets: %w", err)
	}
	return list, nil
}

// UploadWatermark copies a custom watermark image to storage and returns the saved entity.
func (a *App) UploadWatermark(filePath string) (entity.Watermark, error) {
