import { useState } from 'react'
import { useShallow } from 'zustand/shallow'
import type { View } from './types'
import ContactList from './components/address/ContactList'
import PreviewArea from './components/preview/PreviewArea'
import DecorationSidebar from './components/decoration/DecorationSidebar'
import LabelSettingsPanel from './components/label/LabelSettingsPanel'
import PrintConfirmDialog from './components/PrintConfirmDialog'
import { useDecorationStore } from './stores/decorationStore'
import { useLabelStore } from './stores/labelStore'
import { useContactStore } from './stores/contactStore'

function App() {
  const [view, setView] = useState<View>('contacts')
  const [showPrintDialog, setShowPrintDialog] = useState(false)

  const { showDecoPanel, toggleDecoPanel } = useDecorationStore(
    useShallow((s) => ({ showDecoPanel: s.showDecoPanel, toggleDecoPanel: s.toggleDecoPanel })),
  )
  const { showPanel: showLabelPanel, togglePanel: toggleLabelPanel } = useLabelStore(
    useShallow((s) => ({ showPanel: s.showPanel, togglePanel: s.togglePanel })),
  )
  const selectedCount = useContactStore((s) => s.selectedIds.size)

  const showPreview = view === 'contacts' || view === 'preview'

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900">
      {/* サイドバー */}
      <nav className="w-48 bg-white border-r border-gray-200 flex flex-col p-3 gap-1 shrink-0">
        <h1 className="text-sm font-bold px-2 py-3 text-gray-700">Atena ラベル印刷</h1>
        <NavButton active={view === 'contacts'} onClick={() => setView('contacts')}>
          住所録
        </NavButton>
        <NavButton active={view === 'preview'} onClick={() => setView('preview')}>
          ラベルプレビュー
        </NavButton>
        <NavButton active={view === 'settings'} onClick={() => setView('settings')}>
          設定
        </NavButton>
      </nav>

      {/* メインコンテンツ */}
      <main className="flex-1 flex overflow-hidden">
        {view === 'contacts' && (
          <div className="w-72 border-r border-gray-200 bg-white flex flex-col h-full">
            <ContactList />
          </div>
        )}
        {showPreview && (
          <>
            <div className="flex-1 flex flex-col overflow-hidden min-w-0">
              {/* トップバー */}
              <div className="flex items-center justify-end gap-2 px-4 py-2 bg-white border-b border-gray-200 shrink-0">
                <button
                  onClick={toggleLabelPanel}
                  className={`px-3 py-1.5 text-xs rounded border transition-colors ${
                    showLabelPanel
                      ? 'bg-green-50 border-green-400 text-green-700'
                      : 'border-gray-300 text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  ラベル設定
                </button>
                <button
                  onClick={toggleDecoPanel}
                  className={`px-3 py-1.5 text-xs rounded border transition-colors ${
                    showDecoPanel
                      ? 'bg-blue-50 border-blue-400 text-blue-700'
                      : 'border-gray-300 text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  デザイン設定
                </button>
                <button
                  onClick={() => setShowPrintDialog(true)}
                  disabled={selectedCount === 0}
                  className="px-3 py-1.5 text-xs rounded bg-blue-600 text-white hover:bg-blue-700 disabled:opacity-40"
                >
                  ラベル印刷 {selectedCount > 0 && `(${selectedCount}件)`}
                </button>
              </div>
              <PreviewArea />
            </div>
            {showLabelPanel && (
              <div className="w-60 bg-white border-l border-gray-200 flex flex-col h-full shrink-0">
                <div className="px-4 py-3 border-b border-gray-200">
                  <h2 className="text-sm font-semibold text-gray-700">ラベル設定</h2>
                </div>
                <div className="flex-1 overflow-y-auto p-4">
                  <LabelSettingsPanel />
                </div>
              </div>
            )}
            {showDecoPanel && <DecorationSidebar />}
          </>
        )}
        {view === 'settings' && (
          <div className="flex-1 p-6">
            <h2 className="text-xl font-semibold mb-4">設定</h2>
            <p className="text-gray-500">Phase 6 で実装予定</p>
          </div>
        )}
      </main>

      {showPrintDialog && <PrintConfirmDialog onClose={() => setShowPrintDialog(false)} />}
    </div>
  )
}

function NavButton({
  active,
  onClick,
  children,
}: {
  active: boolean
  onClick: () => void
  children: React.ReactNode
}) {
  return (
    <button
      onClick={onClick}
      className={`text-left px-3 py-2 rounded-md text-sm transition-colors ${
        active
          ? 'bg-blue-50 text-blue-700 font-medium'
          : 'text-gray-600 hover:bg-gray-100'
      }`}
    >
      {children}
    </button>
  )
}

export default App

import { useState } from 'react'
import { GenerateLabelPDF, GetTempPDFPath, PrintPDF, SavePDFFileDialog } from '../../wailsjs/go/main/App'
import { entity } from '../../wailsjs/go/models'
import { useContactStore } from '../stores/contactStore'
import { useDecorationStore } from '../stores/decorationStore'
import { useLabelStore } from '../stores/labelStore'
import { useShallow } from 'zustand/shallow'

interface Props {
  onClose: () => void
}

export default function PrintConfirmDialog({ onClose }: Props) {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const { contacts, selectedIds } = useContactStore(
    useShallow((s) => ({ contacts: s.contacts, selectedIds: s.selectedIds })),
  )
  const { watermark, qrConfig } = useDecorationStore(
    useShallow((s) => ({ watermark: s.watermark, qrConfig: s.qrConfig })),
  )
  const layout = useLabelStore((s) => s.layout)

  const selectedContacts = contacts.filter((c) => selectedIds.has(c.id))
  const count = selectedContacts.length

  const paperLabel = `${layout.paperWidth}×${layout.paperHeight}mm (${layout.columns}列×${layout.rows}行)`

  function buildJob(): entity.PrintJob {
    return entity.PrintJob.createFrom({
      contactIds: selectedContacts.map((c) => c.id),
      template: {
        id: '',
        name: 'default',
        orientation: 'vertical',
        labelWidth: layout.labelWidth,
        labelHeight: layout.labelHeight,
        recipient: { nameX: 0, nameY: 0, nameFont: 0, addressX: 0, addressY: 0, addressFont: 0 },
        sender: { nameX: 0, nameY: 0, nameFont: 0, addressX: 0, addressY: 0, addressFont: 0 },
      },
      senderId: '',
      labelLayout: layout,
      watermark: watermark ?? undefined,
      qrConfig: qrConfig.enabled ? qrConfig : undefined,
    })
  }

  async function run(action: () => Promise<void>) {
    setError(null)
    setLoading(true)
    try {
      await action()
      onClose()
    } catch (e) {
      setError(String(e))
    } finally {
      setLoading(false)
    }
  }

  function handleSavePDF() {
    return run(async () => {
      const savePath = await SavePDFFileDialog('ラベル.pdf')
      if (!savePath) return
      await GenerateLabelPDF(buildJob(), savePath)
    })
  }

  function handlePrint() {
    return run(async () => {
      const tmpPath = await GetTempPDFPath()
      const outPath = await GenerateLabelPDF(buildJob(), tmpPath)
      await PrintPDF(outPath)
    })
  }

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl w-80 p-6 space-y-4">
        <h2 className="text-base font-semibold text-gray-800">印刷確認</h2>

        <div className="space-y-2 text-sm text-gray-700">
          <div className="flex justify-between">
            <span className="text-gray-500">印刷枚数</span>
            <span className="font-medium">{count} 件</span>
          </div>
          <div className="flex justify-between">
            <span className="text-gray-500">用紙</span>
            <span className="font-medium text-right">{paperLabel}</span>
          </div>
        </div>

        {error && (
          <p className="text-xs text-red-600 bg-red-50 rounded px-2 py-1">{error}</p>
        )}

        <div className="flex flex-col gap-2 pt-1">
          <button
            onClick={handlePrint}
            disabled={loading || count === 0}
            className="w-full px-4 py-2 bg-blue-600 text-white rounded text-sm font-medium hover:bg-blue-700 disabled:opacity-50"
          >
            {loading ? '処理中...' : '印刷'}
          </button>
          <button
            onClick={handleSavePDF}
            disabled={loading || count === 0}
            className="w-full px-4 py-2 border border-gray-300 text-gray-700 rounded text-sm hover:bg-gray-50 disabled:opacity-50"
          >
            PDF保存
          </button>
          <button
            onClick={onClose}
            disabled={loading}
            className="w-full px-4 py-2 text-gray-500 text-sm hover:text-gray-700"
          >
            キャンセル
          </button>
        </div>
      </div>
    </div>
  )
}

package main

import (
	"embed"
	"log"
	"os"
	"path/filepath"

	"github.com/wailsapp/wails/v2"
	"github.com/wailsapp/wails/v2/pkg/options"
	"github.com/wailsapp/wails/v2/pkg/options/assetserver"

	csvpkg "atena-label/internal/infrastructure/csv"
	imagepkg "atena-label/internal/infrastructure/image"
	pdfpkg "atena-label/internal/infrastructure/pdf"
	"atena-label/internal/infrastructure/postal"
	"atena-label/internal/infrastructure/printer"
	qrpkg "atena-label/internal/infrastructure/qr"
	dbpkg "atena-label/internal/infrastructure/sqlite"
	"atena-label/internal/usecase"
)

//go:embed all:frontend/dist
var assets embed.FS

func main() {
	appDataDir, err := resolveDataDir()
	if err != nil {
		log.Fatal("data dir:", err)
	}

	db, err := dbpkg.Open(filepath.Join(appDataDir, "atena.db"))
	if err != nil {
		log.Fatal("Open DB:", err)
	}
	defer db.Close()

	contactRepo := dbpkg.NewContactRepo(db)
	contactUC := usecase.NewContactUseCase(contactRepo)
	csvUC := usecase.NewCSVUseCase(contactRepo, csvpkg.NewAdapter())
	groupRepo := dbpkg.NewGroupRepo(db)
	groupUC := usecase.NewGroupUseCase(groupRepo)
	watermarkRepo := dbpkg.NewWatermarkRepo(db)
	watermarkUC := usecase.NewWatermarkUseCase(watermarkRepo, &imagepkg.FileStorage{}, filepath.Join(appDataDir, "watermarks"))
	qrCodeUC := usecase.NewQRCodeUseCase(&qrpkg.Generator{})

	senderRepo := dbpkg.NewSenderRepo(db)
	pdfGen := pdfpkg.NewGenerator("")
	printUC := usecase.NewPrintUseCase(contactRepo, senderRepo, pdfGen, &printer.OSPrinter{})

	postalRepo := postal.NewRepo()
	app := NewApp(contactUC, csvUC, groupUC, watermarkUC, qrCodeUC, printUC, postalRepo)

	err = wails.Run(&options.App{
		Title:  "Atena ラベル印刷",
		Width:  1280,
		Height: 800,
		AssetServer: &assetserver.Options{
			Assets: assets,
		},
		BackgroundColour: &options.RGBA{R: 255, G: 255, B: 255, A: 1},
		OnStartup:        app.startup,
		Bind: []interface{}{
			app,
		},
	})

	if err != nil {
		log.Println("Error:", err.Error())
	}
}

func resolveDataDir() (string, error) {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	dir := filepath.Join(homeDir, ".atena-label")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return "", err
	}
	return dir, nil
}

