    useShallow((s) => ({ showPanel: s.showPanel, togglePanel: s.togglePanel })),
  )
  const selectedCount = useContactStore((s) => s.selectedIds.size)

  const showPreview = view === 'contacts' || view === 'preview'

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900">
      {/* サイドバー */}
      <nav className="w-48 bg-white border-r border-gray-200 flex flex-col p-3 gap-1 shrink-0">
        <h1 className="text-sm font-bold px-2 py-3 text-gray-700">Atena ラベル印刷</h1>
        <NavButton active={view === 'contacts'} onClick={() => setView('contacts')}>
          住所録
        </NavButton>
        <NavButton active={view === 'preview'} onClick={() => setView('preview')}>
          ラベルプレビュー
        </NavButton>
        <NavButton active={view === 'senders'} onClick={() => setView('senders')}>
          差出人管理
        </NavButton>
        <NavButton active={view === 'settings'} onClick={() => setView('settings')}>
          設定
        </NavButton>
      </nav>

      {/* メインコンテンツ */}
      <main className="flex-1 flex overflow-hidden">
        {view === 'contacts' && (
          <div className="w-72 border-r border-gray-200 bg-white flex flex-col h-full">
            <ContactList />
          </div>
        )}
        {showPreview && (
          <>
            <div className="flex-1 flex flex-col overflow-hidden min-w-0">
              {/* トップバー */}
              <div className="flex items-center justify-end gap-2 px-4 py-2 bg-white border-b border-gray-200 shrink-0">
                <button
                  onClick={toggleLabelPanel}
                  className={`px-3 py-1.5 text-xs rounded border transition-colors ${
                    showLabelPanel
                      ? 'bg-green-50 border-green-400 text-green-700'
                      : 'border-gray-300 text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  ラベル設定
                </button>
                <button
                  onClick={toggleDecoPanel}
                  className={`px-3 py-1.5 text-xs rounded border transition-colors ${
                    showDecoPanel
                      ? 'bg-blue-50 border-blue-400 text-blue-700'
                      : 'border-gray-300 text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  デザイン設定
                </button>
                <button
                  onClick={() => setShowPrintDialog(true)}
                  disabled={selectedCount === 0}
                  className="px-3 py-1.5 text-xs rounded bg-blue-600 text-white hover:bg-blue-700 disabled:opacity-40"
                >
                  ラベル印刷 {selectedCount > 0 && `(${selectedCount}件)`}
                </button>
              </div>
              <PreviewArea />
            </div>
            {showLabelPanel && (
              <div className="w-60 bg-white border-l border-gray-200 flex flex-col h-full shrink-0">
                <div className="px-4 py-3 border-b border-gray-200">
                  <h2 className="text-sm font-semibold text-gray-700">ラベル設定</h2>
                </div>
                <div className="flex-1 overflow-y-auto p-4">
                  <LabelSettingsPanel />
                </div>
              </div>
            )}
            {showDecoPanel && <DecorationSidebar />}
          </>
        )}
        {view === 'senders' && (
          <div className="flex-1 overflow-y-auto">
            <SenderManager />
          </div>
        )}
        {view === 'settings' && (
          <div className="flex-1 p-6">
            <h2 className="text-xl font-semibold mb-4">設定</h2>
            <p className="text-gray-500">Phase 6 で実装予定</p>
          </div>
        )}
      </main>

      {showPrintDialog && <PrintConfirmDialog onClose={() => setShowPrintDialog(false)} />}
    </div>
  )
}

function NavButton({
  active,
  onClick,
  children,
}: {
  active: boolean
  onClick: () => void
  children: React.ReactNode
}) {
  return (
    <button
      onClick={onClick}
      className={`text-left px-3 py-2 rounded-md text-sm transition-colors ${
        active
          ? 'bg-blue-50 text-blue-700 font-medium'
          : 'text-gray-600 hover:bg-gray-100'
      }`}
    >
      {children}
    </button>
  )
}

export default App

